INSERT INTO asset_column_def(
    column_key, column_label, value_type, sortable, searchable, sort_order, create_by
) VALUES (
    #{columnKey}, #{columnLabel}, #{valueType}, #{sortable}, #{searchable}, #{sortOrder}, #{createBy}
)

INSERT INTO asset_record(
    id, asset_code, asset_name, status, location, locked, note, create_by, update_by
) VALUES (
    #{id}, #{assetCode}, #{assetName}, #{status}, #{location}, #{locked}, #{note}, #{createBy}, #{updateBy}
)

mapper.select:
SELECT asset_id, column_key, column_value
FROM asset_record_value
WHERE asset_id = #{assetId}

mapper.insert:
INSERT INTO asset_transfer_request(
    id, asset_id, asset_code, asset_name, applicant_id, applicant_name, transfer_time,
    transfer_location, from_location, remark, photo_url, photo_urls_before, photo_urls_after, status, create_time
) VALUES (
    #{id}, #{assetId}, #{assetCode}, #{assetName}, #{applicantId}, #{applicantName}, #{transferTime},
    #{transferLocation}, #{fromLocation}, #{remark}, #{photoUrl}, #{photoUrlsBefore}, #{photoUrlsAfter}, #{status}, #{createTime}
)

mapper.update:
UPDATE asset_transfer_request
SET photo_urls_after = #{photoUrlsAfterJson}
WHERE id = #{id}
  AND status = 'IN_PROGRESS'

UPDATE asset_transfer_request
SET status = #{status}
WHERE id = #{id}
  AND status = #{expectedCurrentStatus}

mapper.insert:
INSERT INTO asset_transfer_log(
    id, request_id, asset_id, action_type, operator_id, remark, create_time
) VALUES (
    #{id}, #{requestId}, #{assetId}, #{actionType}, #{operatorId}, #{remark}, #{createdTime}
)

mapper.select:
SELECT r.* FROM asset_transfer_request r WHERE 1=1
AND ( r.asset_code LIKE CONCAT('%', #{keyword}, '%') OR r.asset_name LIKE CONCAT('%', #{keyword}, '%') OR r.transfer_location LIKE CONCAT('%', #{keyword}, '%') OR r.applicant_name LIKE CONCAT('%', #{keyword}, '%') OR r.remark LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY r.create_time DESC LIMIT #{limit} OFFSET #{offset}

mapper.insert:
INSERT INTO asset_transfer_export_file(
    id, request_id, file_name, storage_key, download_token, status, expire_at, summary_text, created_by, created_time
) VALUES (
    #{id}, #{requestId}, #{fileName}, #{storageKey}, #{downloadToken}, #{status}, #{expireAt}, #{summaryText}, #{createdBy}, #{createdTime}
)

mapper.select:
SELECT *
FROM asset_transfer_export_file
WHERE request_id = #{requestId}
ORDER BY created_time DESC
LIMIT #{limit}

SELECT DISTINCT column_value FROM asset_record_value WHERE column_key IN
#{key}
AND column_value IS NOT NULL AND column_value != '' ORDER BY column_value ASC

SELECT * FROM asset_record WHERE deleted = 1
AND ( asset_code LIKE CONCAT('%', #{keyword}, '%') OR asset_name LIKE CONCAT('%', #{keyword}, '%') OR location LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY deleted_time DESC, update_time DESC LIMIT #{limit} OFFSET #{offset}
